insert into public.sources (id, source_key, title, kind, url, show_by_default) values ('00000000-0000-4000-8000-000000000001', 'shimamotor-acro-level-test', '島本アクロレッスン レベルテスト', 'pdf', 'https://www.dropbox.com/scl/fi/5efdb2q2boi3ripstgymy/.pdf?rlkey=0gt6arv6rv5srkidk21y0u7ev&st=bszy3coz&e=1&dl=0', false) on conflict (source_key) do nothing;
insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000001', 't001-30', 'ブリッジ30秒', array[]::text[], '体操 / 倒立・床基礎の最初に固めたい基礎技。肩、体幹、受け身を整え、手支持や床支持の姿勢を崩さないことが重要です。', 'ブリッジ30秒は、体操の要素を持つ倒立・床基礎系の技です。レベル1「倒立系」では「記載技をすべてクリア」が目安です。肩、体幹、受け身を整え、手支持や床支持の姿勢を崩さないことが重要です。 前提技・派生技・近い技は相関図で確認できます。', 1, 1, '体操', '倒立・床基礎', '移動・切り返し', '未設定', '未設定', '縄内アップ', array['体操', '倒立・床基礎', 'Lv.1'], 1, '倒立系', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000002', 't002', '前回り受け身', array[]::text[], 'ダブルダッチ / 基礎ムーブの最初に固めたい基礎技。縄のリズムを崩さず、踏み替えや床移動を安定させることが練習の軸になります。', '前回り受け身は、ダブルダッチの要素を持つ基礎ムーブ系の技です。レベル1「倒立系」では「記載技をすべてクリア」が目安です。縄のリズムを崩さず、踏み替えや床移動を安定させることが練習の軸になります。 前提技・派生技・近い技は相関図で確認できます。', 1, 1, 'ダブルダッチ', '基礎ムーブ', '移動・切り返し', '未設定', '未設定', '縄内アップ', array['ダブルダッチ', '基礎ムーブ', 'Lv.1'], 1, '倒立系', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
