insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000016', 't016-30', 'チェアー30秒', array[]::text[], 'ブレイキン / 倒立・床基礎の最初に固めたい基礎技。肩、体幹、受け身を整え、手支持や床支持の姿勢を崩さないことが重要です。', 'チェアー30秒は、ブレイキンの要素を持つ倒立・床基礎系の技です。レベル2「倒立系」では「記載技をすべてクリア」が目安です。肩、体幹、受け身を整え、手支持や床支持の姿勢を崩さないことが重要です。 前提技・派生技・近い技は相関図で確認できます。', 2, 1, 'ブレイキン', '倒立・床基礎', '移動・切り返し', '未設定', '未設定', '縄内アップ', array['ブレイキン', '倒立・床基礎', 'Lv.2'], 2, '倒立系', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
