insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000058', 't058', 'ライズ', array[]::text[], 'カポエイラ / トリッキングの演技に入れやすい発展技。手支持と蹴り上げの軌道を滑らかにつなぎ、勢いを止めずに切り返します。', 'ライズは、カポエイラの要素を持つトリッキング系の技です。レベル6「小技発展」では「以下の技から6個クリアで合格」が目安です。手支持と蹴り上げの軌道を滑らかにつなぎ、勢いを止めずに切り返します。 前提技・派生技・近い技は相関図で確認できます。', 3, 3, 'カポエイラ', 'トリッキング', '移動・切り返し', '未設定', '未設定', '縄内単発', array['カポエイラ', 'トリッキング', 'Lv.6'], 6, '小技発展', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
