insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000060', 't060', '側転ツイスト', array[]::text[], '体操 / ひねりの演技に入れやすい発展技。回転にひねりを加えるため、目線、締め、着地方向を前提技で確認してから扱います。', '側転ツイストは、体操の要素を持つひねり系の技です。レベル6「小技発展」では「以下の技から6個クリアで合格」が目安です。回転にひねりを加えるため、目線、締め、着地方向を前提技で確認してから扱います。 前提技・派生技・近い技は相関図で確認できます。', 3, 3, '体操', 'ひねり', 'ひねり軸', '未設定', '未設定', '縄内単発', array['体操', 'ひねり', 'Lv.6'], 6, '小技発展', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000061', 't061', 'エアツイガンビ', array[]::text[], 'カポエイラ / トリッキングの演技に入れやすい発展技。手支持と蹴り上げの軌道を滑らかにつなぎ、勢いを止めずに切り返します。', 'エアツイガンビは、カポエイラの要素を持つトリッキング系の技です。レベル6「小技発展」では「以下の技から6個クリアで合格」が目安です。手支持と蹴り上げの軌道を滑らかにつなぎ、勢いを止めずに切り返します。 前提技・派生技・近い技は相関図で確認できます。', 3, 3, 'カポエイラ', 'トリッキング', '移動・切り返し', '未設定', '未設定', '縄内単発', array['カポエイラ', 'トリッキング', 'Lv.6'], 6, '小技発展', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000062', 't062-540', '540', array[]::text[], 'トリッキング / トリッキングの演技に入れやすい発展技。片足踏切や斜めの軌道を使うので、入り方と着地後の流れまでセットで見ます。', '540は、トリッキングの要素を持つトリッキング系の技です。レベル6「小技発展」では「以下の技から6個クリアで合格」が目安です。片足踏切や斜めの軌道を使うので、入り方と着地後の流れまでセットで見ます。 前提技・派生技・近い技は相関図で確認できます。', 3, 3, 'トリッキング', 'トリッキング', '移動・切り返し', '未設定', '未設定', '縄内単発', array['トリッキング', 'トリッキング', 'Lv.6'], 6, '小技発展', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
