insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000069', 't069', 'コインドロップ', array[]::text[], 'ブレイキン / ブレイキン・床回転の演技に入れやすい発展技。床支持の形、重心移動、回転の継続を安全に作ることが練習の中心です。', 'コインドロップは、ブレイキンの要素を持つブレイキン・床回転系の技です。レベル6「小技発展」では「以下の技から6個クリアで合格」が目安です。床支持の形、重心移動、回転の継続を安全に作ることが練習の中心です。 前提技・派生技・近い技は相関図で確認できます。', 3, 3, 'ブレイキン', 'ブレイキン・床回転', '床回転', '未設定', '未設定', '縄内単発', array['ブレイキン', 'ブレイキン・床回転', 'Lv.6'], 6, '小技発展', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
