insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000108', 't108', '前宙ひねり', array[]::text[], '体操 / ひねりの演技に入れやすい発展技。回転にひねりを加えるため、目線、締め、着地方向を前提技で確認してから扱います。', '前宙ひねりは、体操の要素を持つひねり系の技です。レベル8「空中系応用」では「以下の技から3個クリアで合格」が目安です。回転にひねりを加えるため、目線、締め、着地方向を前提技で確認してから扱います。 前提技・派生技・近い技は相関図で確認できます。', 4, 4, '体操', 'ひねり', 'ひねり軸', '未設定', '未設定', '縄内単発', array['体操', 'ひねり', 'Lv.8'], 8, '空中系応用', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
insert into public.tricks (id, slug, name, aliases, summary, description, difficulty, risk_level, discipline, family, axis, takeoff, landing, rope_context, tags, level, level_category, status, source_id, show_source) values ('00000000-0000-4000-9000-000000000109', 't109', '逆宙', array[]::text[], '体操 / 空中回転の演技に入れやすい発展技。踏切の高さ、回転姿勢、着地の向きを分けて確認しながら段階的に練習します。', '逆宙は、体操の要素を持つ空中回転系の技です。レベル8「空中系応用」では「以下の技から3個クリアで合格」が目安です。踏切の高さ、回転姿勢、着地の向きを分けて確認しながら段階的に練習します。 前提技・派生技・近い技は相関図で確認できます。', 4, 4, '体操', '空中回転', '縦・横回転', '未設定', '未設定', '縄内単発', array['体操', '空中回転', 'Lv.8'], 8, '空中系応用', 'published', '00000000-0000-4000-8000-000000000001', false) on conflict (slug) do update set summary = excluded.summary, description = excluded.description, difficulty = excluded.difficulty, risk_level = excluded.risk_level, discipline = excluded.discipline, family = excluded.family, axis = excluded.axis, takeoff = excluded.takeoff, landing = excluded.landing, rope_context = excluded.rope_context, tags = excluded.tags, level = excluded.level, level_category = excluded.level_category, status = excluded.status, source_id = excluded.source_id;
